# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql

def lambda_handler(event, context):
    # Database configuration
    rds_host  = "your-rds-endpoint"
    username = "your-username"
    password = "your-password"
    db_name = "your-database"

    # Create database connection
    connection = pymysql.connect(host=rds_host, user=username, password=password, db=db_name, connect_timeout=5)
    
    search_conditions = []
    values = []

    # Sample search parameters in event
    search_params = event.get('queryStringParameters', {})
    
    # Building dynamic query
    if 'name' in search_params:
        search_conditions.append("name LIKE %s")
        values.append(f"%{search_params['name']}%")
    if 'category' in search_params:
        search_conditions.append("category = %s")
        values.append(search_params['category'])
    if 'price_min' in search_params:
        search_conditions.append("price >= %s")
        values.append(search_params['price_min'])
    if 'price_max' in search_params:
        search_conditions.append("price <= %s")
        values.append(search_params['price_max'])
    
    condition_string = " AND ".join(search_conditions)
    query = f"SELECT * FROM products"
    if condition_string:
        query += f" WHERE {condition_string}"
    
    try:
        with connection.cursor() as cursor:
            cursor.execute(query, values)
            result = cursor.fetchall()
        
        return {
            'statusCode': 200,
            'body': json.dumps(result)
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
    finally:
        connection.close()